array_map(
			function ( $init_file ) {
				$name = get_plugin_data( WP_PLUGIN_DIR . '/' . $init_file )['Name'] ?? '';
				if ( ! $name ) {
					$name = str_replace( array( '-', 'init.php', '/' ), ' ', $init_file );
					$name = str_replace( array( 'yith', 'woocommerce', 'wordpress' ), array( 'YITH', 'WooCommerce', 'WordPress' ), $name );
